import React from 'react';
import { BrowserRouter, Routes, Route } from 'react-router-dom';
import Navbar from './components/Navbar';
<Route path="/" element={<Home />} />


function App() {
  return (
    <BrowserRouter>

      <Navbar />

      <div style={{ paddingTop: 56 }}>
        <Routes>
          <Route path="/" element={<Home />} />
          <Route path="/overview" element={<h1 style={{ padding: 40, color: 'white' }}>Overview Page</h1>} />
          <Route path="/trends" element={<h1 style={{ padding: 40, color: 'white' }}>Trends Page</h1>} />
          <Route path="/cities" element={<h1 style={{ padding: 40, color: 'white' }}>Cities Page</h1>} />
        </Routes>
      </div>

    </BrowserRouter>
  );
}

export default App;
